md\",\n      \"stage\": \"spec-review\",\n      \"must_include\": [\"adversarial\", \"contradictions\", \"testability gaps\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/spec-consensus.md\",\n      \"stage\": \"spec\",\n      \"must_include\": [\"Research Evidence\", \"Boilerplate Reuse\", \"Appium Exploratory QA\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/spec-red-team.md\",\n      \"stage\": \"spec-review\",\n      \"must_include\": [\"VERDICT: APPROVED\", \"VERDICT: REJECTED\", \"release criteria\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/architecture-candidate.md\",\n      \"stage\": \"architecture\",\n      \"must_include\": [\"extends SwiftAIBoilerplatePro\", \"CompositionRoot\", \"Appium\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/architecture-consensus.md\",\n      \"stage\": \"architecture\",\n      \"must_include\": [\"architecture.md\", \"adr.md\", \"Packages/Core\", \"CompositionRoot\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/boilerplate-setup.md\",\n      \"stage\": \"implementation\",\n      \"must_include\": [\"do not recreate\", \"AGENTS.md\", \"DISTRIBUTION_README.md\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/implement-foundation.md\",\n      \"stage\": \"implementation\",\n      \"must_include\": [\"BrandConfig\", \"secrets\", \"Appium exploratory\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/implement-core.md\",\n      \"stage\": \"implementation\",\n      \"must_include\": [\"repositories\", \"ViewModel\", \"unit tests\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/implement-interface.md\",\n      \"stage\": \"implementation\",\n      \"must_include\": [\"DesignSystem\", \"accessibility\", \"actual app experience\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/implement-integration.md\",\n      \"stage\": \"implementation\",\n      \"must_include\": [\"xcodebuild\", \"SwiftLint\", \"SwiftFormat\", \"Appium\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/verify-phase.md\",\n      \"stage\": \"verify\",\n      \"must_include\": [\"independently verify\", \"boilerplate conventions\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-implementation-correctness.md\",\n      \"stage\": \"code-review\",\n      \"must_include\": [\"correctness\", \"spec.md\", \"blocking\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-implementation-tests.md\",\n      \"stage\": \"code-review\",\n      \"must_include\": [\"tests\", \"xcodebuild\", \"Appium\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-implementation-security.md\",\n      \"stage\": \"code-review\",\n      \"must_include\": [\"security\", \"privacy\", \"secrets\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-implementation-boilerplate.md\",\n      \"stage\": \"code-review\",\n      \"must_include\": [\"SwiftAIBoilerplatePro\", \"boilerplate\", \"unnecessary rebuild\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-implementation-consensus.md\",\n      \"stage\": \"code-review\",\n      \"must_include\": [\"implementation-consensus.md\", \"VERDICT: APPROVED\", \"VERDICT: REJECTED\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/simplification.md\",\n      \"stage\": \"simplify\",\n      \"must_include\": [\"split Swift files\", \"400 lines\", \"do not remove quality gates\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/ai-ui-explorer.md\",\n      \"stage\": \"qa\",\n      \"must_include\": [\"tap every reachable\", \"reports/ios/appium-exploratory-report.json\", \"crashes\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/app-store-hardening.md\",\n      \"stage\": \"release\",\n      \"must_include\": [\"SwiftAI\", \"Boilerplate\", \"release strings audit: PASS\", \"Privacy\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-product-fidelity.md\",\n      \"stage\": \"final-review\",\n      \"must_include\": [\"spec.md\", \"research synthesis\", \"template-like\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-ios-architecture.md\",\n      \"stage\": \"final-review\",\n      \"must_include\": [\"architecture.md\", \"Swift 6\", \"CompositionRoot\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-security-privacy.md\",\n      \"stage\": \"final-review\",\n      \"must_include\": [\"Security\", \"Privacy\", \"hardcoded secrets\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-code-quality.md\",\n      \"stage\": \"final-review\",\n      \"must_include\": [\"SwiftLint\", \"SwiftFormat\", \"Qlty\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-release-readiness.md\",\n      \"stage\": \"final-review\",\n      \"must_include\": [\"iOS CI report\", \"TestFlight\", \"macOS/Xcode\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/review-qa-evidence.md\",\n      \"stage\": \"final-review\",\n      \"must_include\": [\"Appium\", \"button tap coverage\", \"crashes\"]\n    },\n    {\n      \"path\": \"prompts/iphone-app-factory/final-consensus.md\",\n      \"stage\": \"final-review\",\n      \"must_include\": [\"VERDICT: APPROVED\", \"VERDICT: REJECTED\", \"boilerplate\"]\n    }\n  ]\n}\n\nGolden cases:\n{\"id\":\"spec-lab\",\"input\":\"The spec lab prompts should force independent candidates, adversarial critique, consensus, red team, and a testable Definition of Done.\",\"expected_quality\":[\"independent candidates\",\"adversarial critique\",\"consensus merge\",\"red team verdict\",\"testable Definition of Done\"]}\n{\"id\":\"boilerplate-first\",\"input\":\"Implementation prompts should bias agents to extend SwiftAIBoilerplatePro instead of rebuilding auth, payments, AI, storage, networking, localization, settings, or design system.\",\"expected_quality\":[\"boilerplate reuse\",\"module boundaries\",\"CompositionRoot\",\"no platform rewrite\",\"App Store 4.3 awareness\"]}\n{\"id\":\"ios-qa\",\"input\":\"Quality prompts should require macOS Xcode evidence, strict Swift lint/format/static checks, sensitive-value scanning, Appium/XCUITest exploratory clicking, and release string audits.\",\"expected_quality\":[\"xcodebuild build/test\",\"SwiftLint\",\"SwiftFormat\",\"Qlty\",\"sensitive scan\",\"Appium exploratory tapping\",\"release string audit\"]}\n{\"id\":\"mobbin-safe\",\"input\":\"Design research prompts may use Mobbin credential env vars but should not leak credentials, clone screens, or copy assets.\",\"expected_quality\":[\"credential env vars\",\"no secret logging\",\"pattern abstraction\",\"no cloning\",\"Apple HIG or DesignSystem cross-check\"]}\n\nRepresentative prompts:\nSPEC_CONSENSUS:\n# Spec Consensus\n\nRead:\n\n- `.workflow/iphone-app-factory/research-synthesis.md`\n- `.workflow/iphone-app-factory/opportunity-matrix.json`\n- all spec candidate outputs in context\n- `.workflow/iphone-app-factory/spec-cross-critique.md`\n- `.workflow/iphone-app-factory/quality-bar.json`\n\nMerge the strongest ideas into one buildable spec.\n\nWrite:\n\n- `.workflow/iphone-app-factory/spec.md`\n- `.workflow/iphone-app-factory/definition-of-done.md`\n- `.workflow/iphone-app-factory/spec-consensus.md`\n\n`spec.md` must include these section headings exactly:\n\n- `# Product Spec`\n- `## Research Evidence`\n- `## User Journeys`\n- `## MVP Scope`\n- `## Boilerplate Reuse`\n- `## Design Direction`\n- `## Acceptance Criteria`\n- `## Appium Exploratory QA`\n- `## App Store Readiness`\n- `## Definition of Done`\n\nThe Definition of Done must be checklist-based and testable.\n\nARCHITECTURE:\n# Architecture And ADR Consensus\n\nRead:\n\n- `.workflow/iphone-app-factory/spec.md`\n- `.workflow/iphone-app-factory/definition-of-done.md`\n- all architecture candidates in context\n- `.workflow/iphone-app-factory/quality-bar.json`\n\nWrite:\n\n- `.workflow/iphone-app-factory/architecture.md`\n- `.workflow/iphone-app-factory/adr.md`\n\nThe architecture must explicitly map the product to SwiftAIBoilerplatePro:\n\n- `SwiftAIBoilerplatePro.xcodeproj`\n- `Config/App.xcconfig`\n- `Packages/Core`\n- `Packages/Networking`\n- `Packages/Storage`\n- `Packages/Auth`\n- `Packages/Payments`\n- `Packages/AI`\n- `Packages/FeatureSettings`\n- `Packages/Localization`\n- `Packages/DesignSystem`\n- `CompositionRoot`\n\nIf any module is removed, the ADR must explain dependency order and App Store 4.3 consequences.\n\nIMPLEMENT_INTEGRATION:\n# Implement Integration Phase\n\nImplement only the integration and release-hardening phase in `{{ inputs.app_dir|default(\"apps/generated-iphone-app\") }}`.\n\nScope:\n\n- wire feature into CompositionRoot/AppShell\n- complete tests and UI test fixtures\n- complete `scripts/ci/ios-quality.sh`\n- complete `.github/workflows/ios-quality.yml`\n- complete Appium exploratory script\n- generate `reports/ios/ios-quality-report.json` when quality checks pass\n- generate `reports/ios/appium-exploratory-report.json` when Appium checks pass\n- create release/readiness docs\n\nThe CI script must include xcodebuild build/test, SwiftLint, SwiftFormat, Qlty, secret scan, and App Store string audit.\n\nSecret handling is blocking: never print environment variables or credential values. CI and local scripts may verify that required secrets are present, but output must be redacted true/false status only.\n\nWrite `.workflow/iphone-app-factory/evidence/integration.md` with:\n\n- `Files changed`\n- `Commands run`\n- `Acceptance criteria`\n- `Risks`\n\nAI_UI_EXPLORER:\n# AI UI Explorer\n\nRun or complete the automated exploratory UI pass for `{{ inputs.app_dir|default(\"apps/generated-iphone-app\") }}`.\n\nThe target behavior is: launch the iOS app in simulator through Appium/XCUITest and tap every reachable enabled button/control across the MVP flows.\n\nThe explorer should:\n\n- record each screen source or screenshot\n- identify buttons, tabs, cells, navigation controls, and primary actions\n- tap controls breadth-first with a bounded depth\n- recover with back/navigation when possible\n- detect crashes, blank screens, stuck spinners, and unhandled error screens\n- produce `reports/ios/appium-exploratory-report.json`\n\nThe report JSON must include:\n\n```json\n{\n  \"ok\": true,\n  \"buttons_tapped\": 0,\n  \"screens_visited\": 0,\n  \"crashes\": 0,\n  \"failures\": 0,\n  \"failures_detail\": []\n}\n```\n\nDo not mark the pass complete unless a real simulator/Appium run happened, unless the workflow explicitly allows macOS deferral.\n\nFINAL_CONSENSUS:\n# Final Consensus Review\n\nRead:\n\n- `.workflow/iphone-app-factory/spec.md`\n- `.workflow/iphone-app-factory/definition-of-done.md`\n- `.workflow/iphone-app-factory/reviews/product-fidelity.md`\n- `.workflow/iphone-app-factory/reviews/ios-architecture.md`\n- `.workflow/iphone-app-factory/reviews/security-privacy.md`\n- `.workflow/iphone-app-factory/reviews/code-quality.md`\n- `.workflow/iphone-app-factory/reviews/release-readiness.md`\n- `.workflow/iphone-app-factory/reviews/qa-evidence.md`\n- `.workflow/iphone-app-factory/quality-contract-gate.json`\n- `.workflow/iphone-app-factory/ios-ci-gate.json`\n- `.workflow/iphone-app-factory/appium-gate.json`\n- `.workflow/iphone-app-factory/app-store-hardening-gate.json`\n\nMerge the review fanout into a final release decision.\n\nRules:\n\n- If any reviewer finds a blocking issue, reject.\n- If macOS/Xcode or Appium evidence is missing and not explicitly deferred, reject.\n- If the app does not use the boilerplate substantially, reject.\n- If App Store 4.3 hardening did not pass, reject.\n\nWrite `.workflow/iphone-app-factory/final-consensus.md` with:\n\n- reviewer agreement/disagreement\n- blocking issues\n- remaining deferred items\n- release handoff notes\n\nEnd with exactly one verdict line:\n\n`VERDICT: APPROVED`\n\nor\n\n`VERDICT: REJECTED`\n\nReturn valid JSON only, no markdown fences:\n{\"verdict\":\"APPROVE\",\"score\":0.0,\"covered\":[\"spec_lab\",\"boilerplate_reuse\",\"ios_quality\",\"appium_qa\",\"mobbin_safety\",\"release_hardening\"],\"gaps\":[]}\n",
.workflow/iphone-app-factory/evals/promptfoo-output.json:137:          "output": "# Evaluation: iPhone App Factory Prompt Suite\n\n## Overall Assessment: **STRONG BUT WITH CRITICAL GAPS** (7.2/10)\n\nThis is a well-architected prompt suite with excellent structural discipline, but it has **three blocking vulnerabilities** for overnight agentic execution.\n\n---\n\n## Strengths ✅\n\n| Category | Evidence |\n|----------|----------|\n| **Workflow coherence** | Clear stage progression (research → spec → architecture → implementation → review → release) |\n| **Spec lab rigor** | Independent candidates + adversarial critique + red team + consensus pattern is sound |\n| **Boilerplate enforcement** | Multiple checkpoints (spec, architecture, implementation, review) bias toward reuse |\n| **Quality gates** | Explicit xcodebuild, SwiftLint, SwiftFormat, Qlty, Appium requirements |\n| **Verdict discipline** | Binary APPROVED/REJECTED verdicts with blocking rules prevent ambiguous handoffs |\n| **Secret handling intent** | \"Never print environment variables\" appears 6+ times |\n\n---\n\n## Critical Gaps ❌\n\n### 1. **Secret Handling is Underspecified** (BLOCKING)\n\n**Problem:**\n- `research-design-patterns.md` must_include lists `MOBBIN_EMAIL`, `MOBBIN_PASSWORD` but no prompt shows *how* to use them safely\n- `implement-foundation.md` mentions \"secrets\" but doesn't specify injection mechanism\n- No prompt explicitly forbids `os.environ.dump()`, `print(os.environ)`, or credential logging in agent outputs\n- No prompt specifies redaction rules for CI logs\n\n**Risk:** Overnight agent could leak credentials to stdout/logs during research or implementation phases.\n\n**Required fix:**\n```yaml\nmust_include: [\n  \"never print environment variables\",\n  \"use getenv() with redaction wrapper\",\n  \"credential verification: true/false only\",\n  \"no credential values in logs or reports\",\n  \"sanitize all JSON outputs for secrets\"\n]\n```\n\n### 2. **Appium/XCUITest Evidence is Optional** (BLOCKING FOR OVERNIGHT)\n\n**Problem:**\n- `ai-ui-explorer.md` says \"Do not mark the pass complete unless a real simulator/Appium run happened, **unless the workflow explicitly allows macOS deferral**\"\n- `final-consensus.md` says \"If macOS/Xcode or Appium evidence is missing **and not explicitly deferred**, reject\"\n- No prompt defines what \"explicitly deferred\" means or under what conditions it's acceptable\n- Overnight execution on headless CI likely cannot run iOS simulator → creates escape hatch for skipping QA\n\n**Risk:** Agent defers Appium, skips real device testing, ships untested app.\n\n**Required fix:**\n```yaml\n# In final-consensus.md\nRules:\n  - Appium deferral only allowed if:\n    1. Workflow input explicitly sets \"defer_appium: true\"\n    2. A blocking issue prevents simulator setup (documented)",
