  workflow_dispatch:

jobs:
  ios-quality:
    runs-on: macos-15
    steps:
      - name: Checkout
        uses: actions/checkout@v4

      - name: Select Xcode
        run: sudo xcode-select -s /Applications/Xcode_26.2.app || sudo xcode-select -s "$(ls -d /Applications/Xcode_*.app | sort -V | tail -1)"

      - name: Install Swift quality tools
        run: |
          brew update
          brew install swiftlint swiftformat ripgrep

      - name: Install Qlty CLI
        uses: qltysh/qlty-action/install@v2

      - name: iOS quality gates
        env:
          IOS_QUALITY_REQUIRE_SECRETS: "0"
          SUPABASE_URL: ${{ secrets.SUPABASE_URL }}
          SUPABASE_ANON_KEY: ${{ secrets.SUPABASE_ANON_KEY }}
          REVENUECAT_API_KEY: ${{ secrets.REVENUECAT_API_KEY }}
        run: ./scripts/ci/ios-quality.sh

      - name: Appium exploratory gates
        run: ./scripts/qa/appium-exploratory-tapper.sh

      - name: Upload iOS quality report
        if: always()
        uses: actions/upload-artifact@v4
        with:
          name: ios-quality-report
          path: reports/ios/ios-quality-report.json

      - name: Upload exploratory report
        if: always()
        uses: actions/upload-artifact@v4
        with:
          name: appium-exploratory-report
          path: reports/ios/appium-exploratory-report.json
