        result = result.replacingOccurrences(
            of: jwtPattern,
            with: "•••",
            options: .regularExpression
        )

        // Redact long base64-like strings (likely to be tokens/keys)
        let longBase64Pattern = "[a-zA-Z0-9+/=]{20,}"
        result = result.replacingOccurrences(
            of: longBase64Pattern,
            with: "•••",
            options: .regularExpression
        )

        return result
